              <dd className="mt-1">{block.whatItDoes}</dd>
            </div>
            <div>
              <dt className="font-mono text-xs uppercase tracking-widest text-muted">
                What changed
              </dt>
              <dd className="mt-1">{block.whatChanged}</dd>
            </div>
            <div>
              <dt className="font-mono text-xs uppercase tracking-widest text-muted">
